import React,{useCallback,useReducer} from "react";
import Input from "../../shared/components/FormElements/Input";
import Button from"../../shared/components/FormElements/Button";
import { VALIDATOR_MINLENGTH, VALIDATOR_REQUIRE } from "../../shared/util/validators";
import "./NewPlace.css";
import { useFormAction } from "react-router-dom";

const formReducer = (state,action) => {
  switch (action.type){
    case 'INPUT_CHANGE':
      let formIsvalid = true;
      for (const inputId in state .inputs ){
         if(inputId === action.inputId){
          formIsvalid = formIsvalid && action.isvaild;
         } else {
          formIsvalid = formIsvalid && state.inputs[inputId].isvalid;
         }
      }
      return{
        ...state,
        inputs:{
          ...state.inputs,
          [action.inputId]: {value: action.value,isvalue: action.isvalid}
        },
        isvalid: formIsvalid
      };

    default:
      return state;
  }
};

const NewPlace = () => {
 const [formState,dispatch]  = useReducer(formReducer,{
    inputs:{
      title:{
        value:'',
        isvalid:false
      
    },
    description:{
      value:'',
    isvalid:false
    }
  },
  isvalid: false
  });
      constInputHandler = useCallback((id,value,isvalid) => { 
        dispatchEvent({type: 'INPUT_CHANGE',value: value,isvaild: isvalid, inputId: id});
      },[]);

        const DescriptionInptHandler = useCallback((id,value,isvalid) => { },[]);


  return (
    <form className="place-form">
      <Input
        id="title"
        element="input"
        type="text"
        label="Title"
        validators={[VALIDATOR_REQUIRE()]}
        errorText="Please enter a valid title."
        onInput={InputHandler}
      />
      <Input
      id="description"
      element="textarea"
      lable="Description"
      validators={[VALIDATOR_MINLENGTH(5)]}
      errorText="Please enter a valid description (at least 5 characters)."
        onInput={InptHandler}
        />
        <Button type="submit" disabled={!formState.isvalid}>
          ADD PLACE
        </Button>
    </form>
  );
};

export default NewPlace;
